using System.ComponentModel.DataAnnotations;

namespace sv_25233def60c34b1f8d4a37cc649745a9.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    public static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    public Product Clone() => new()
    {
        Id = Id,
        Name = Name,
        Quantity = Quantity,
        UnitPrice = UnitPrice,
        Category = Category
    };
}

using sv_25233def60c34b1f8d4a37cc649745a9.Models;

namespace sv_25233def60c34b1f8d4a37cc649745a9.Services;

public class InventoryService
{
    private readonly Lock _lock = new();

    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.99m, Category = "Food" },
        new Product { Id = 4, Name = "USB-C Hub", Quantity = 60, UnitPrice = 49.95m, Category = "Electronics" },
        new Product { Id = 5, Name = "Granola Bars (12-pack)", Quantity = 200, UnitPrice = 6.49m, Category = "Food" },
        new Product { Id = 6, Name = "Denim Jacket", Quantity = 45, UnitPrice = 59.99m, Category = "Clothing" }
    };

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => p.Clone()).ToList());
        }
    }

    public Task UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == updated.Id)
                ?? throw new InvalidOperationException($"Product with Id {updated.Id} not found.");

            existing.Name = updated.Name;
            existing.Quantity = updated.Quantity;
            existing.UnitPrice = updated.UnitPrice;
            existing.Category = updated.Category;
        }

        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_25233def60c34b1f8d4a37cc649745a9.Models
@using sv_25233def60c34b1f8d4a37cc649745a9.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-bordered">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id)
                {
                    <tr>
                        <td>
                            <input type="text" class="form-control" @bind="_editModel!.Name" />
                            @if (_validationErrors.ContainsKey(nameof(Product.Name)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Name)]</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editModel!.Quantity" />
                            @if (_validationErrors.ContainsKey(nameof(Product.Quantity)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Quantity)]</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" step="0.01" @bind="_editModel!.UnitPrice" />
                            @if (_validationErrors.ContainsKey(nameof(Product.UnitPrice)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.UnitPrice)]</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editModel!.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Product.Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (_validationErrors.ContainsKey(nameof(Product.Category)))
                            {
                                <div class="text-danger small">@_validationErrors[nameof(Product.Category)]</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;
    private Dictionary<string, string> _validationErrors = new();

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        _editingProductId = product.Id;
        _editModel = product.Clone();
        _validationErrors.Clear();
    }

    private void Cancel()
    {
        _editingProductId = null;
        _editModel = null;
        _validationErrors.Clear();
    }

    private bool Validate()
    {
        _validationErrors.Clear();
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
        var context = new ValidationContext(_editModel!);
        Validator.TryValidateObject(_editModel!, context, results, validateAllProperties: true);

        foreach (var result in results)
        {
            foreach (var member in result.MemberNames)
            {
                _validationErrors.TryAdd(member, result.ErrorMessage ?? "Invalid");
            }
        }

        return _validationErrors.Count == 0;
    }

    private async Task SaveAsync()
    {
        if (!Validate())
            return;

        await InventoryService.UpdateAsync(_editModel!);
        _products = await InventoryService.GetAllAsync();
        _editingProductId = null;
        _editModel = null;
    }
}

